export function getDistanceAtTime(ts) {
  if (ts <= DIST_WAYPOINTS[0].t) return DIST_WAYPOINTS[0].d;
  if (ts >= DIST_WAYPOINTS[DIST_WAYPOINTS.length - 1].t) return DIST_WAYPOINTS[DIST_WAYPOINTS.length - 1].d;

  for (let index = 0; index < DIST_WAYPOINTS.length - 1; index += 1) {
    const start = DIST_WAYPOINTS[index];
    const end = DIST_WAYPOINTS[index + 1];
    if (ts >= start.t && ts <= end.t) {
      const fraction = (ts - start.t) / (end.t - start.t);
      return start.d + (end.d - start.d) * fraction;
    }
  }

  return 0;
}

export function getDisplayDistance(ts) {
  if (ts >= SPLASHDOWN_T) return 0;
  if (ts >= LIFTOFF_T && ts < SRB_SEP_T) return -1;
  return getDistanceAtTime(ts);
}

export function formatDistance(miles, useMetric) {
  if (miles === -1) return 'Liftoff';
  if (miles < 0.01) return 'On the ground';

  if (useMetric) {
    const kilometers = miles * 1.60934;
    if (kilometers < 160) {
      return `${Math.round(kilometers * 1000).toLocaleString()} m`;
    }
    return `${Math.round(kilometers).toLocaleString()} km`;
  }

  if (miles < 100) {
    return `${Math.round(miles * 5280).toLocaleString()} ft`;
  }

  return `${Math.round(miles).toLocaleString()} miles`;
}

export function getActivityAt(ts) {
  return SCHEDULE.find((entry) => ts >= entry.s && ts < entry.e) || null;
}

export function getTrajIndex(ts) {
  const elapsed = ts - TRAJ_START;
  const index = elapsed / TRAJ_STEP_SC;
  return Math.max(0, Math.min(TRAJ_SC.length - 1, index));
}

export function interpTraj(points, step, ts) {
  const elapsed = ts - TRAJ_START;
  const floatIndex = elapsed / step;
  const index = Math.max(0, Math.min(points.length - 2, Math.floor(floatIndex)));
  const fraction = Math.max(0, Math.min(1, floatIndex - index));
  const nextIndex = Math.min(index + 1, points.length - 1);

  return [
    points[index][0] + (points[nextIndex][0] - points[index][0]) * fraction,
    points[index][1] + (points[nextIndex][1] - points[index][1]) * fraction,
  ];
}

export function rotXY(x, y) {
  return [x * TRAJ_COS - y * TRAJ_SIN, x * TRAJ_SIN + y * TRAJ_COS];
}

export function getMoonDistKm(ts) {
  const spacecraft = interpTraj(TRAJ_SC, TRAJ_STEP_SC, ts);
  const moon = interpTraj(TRAJ_MOON, TRAJ_STEP_MOON, ts);
  const dx = spacecraft[0] - moon[0];
  const dy = spacecraft[1] - moon[1];
  return Math.sqrt(dx * dx + dy * dy);
}

export function formatMoonDist(moonKm, useMetric) {
  const surfaceDistance = moonKm - MOON_RADIUS_KM;
  if (surfaceDistance <= 0) return 'At the Moon';
  if (useMetric) return `${Math.round(surfaceDistance).toLocaleString()} km`;
  return `${Math.round(surfaceDistance * KM_TO_MI).toLocaleString()} miles`;
}